export interface SimulationState {
  inputAmplitude: number; // A_input: Energy pumped into the channels
  frequency: number; // Omega: The "Om" frequency
  couplingConstant: number; // Alpha: Material coupling
  radius: number; // R: Radius of the sphere (fixed for sim usually, but variable in math)
}

export interface PhysicsResult {
  waveNumber: number; // k
  resonanceQuality: number; // How close to j0(kR)=1
  energyDensity: number; // E_core
  effectiveMass: number; // M_eff
  massReductionPercent: number;
  isLevitating: boolean;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  isThinking?: boolean;
}

import { SimulationState, PhysicsResult } from '../types';
import { INITIAL_MASS_KG, VACUUM_AFFINITY_DENSITY, AFFINITY_SPEED } from '../constants';

// Spherical Bessel function of the first kind j0(x) = sin(x)/x
const j0 = (x: number): number => {
  if (Math.abs(x) < 1e-6) return 1.0;
  return Math.sin(x) / x;
};

export const calculatePhysics = (state: SimulationState): PhysicsResult => {
  const { inputAmplitude, frequency, couplingConstant, radius } = state;

  // 1. Calculate Wavenumber k = omega / c_a
  const k = frequency / AFFINITY_SPEED;

  // 2. Check Resonance Condition: j0(kR) should be close to 1 (Constructive Interference Limit)
  // In reality, j0(x)=1 only at x=0, but for the app we simulate "resonance modes"
  // Let's assume the fundamental mode requires kR to be a specific value or we measure coherence.
  // We'll model "Resonance Quality" as how well the inputs phase align.
  // For the sake of the "Buga" artifact, we assume the geometry forces coherence if frequency matches.
  // We'll define a "target frequency" that is optimal.
  const targetFreq = 1200; // Hz, arbitrary resonance freq
  const detuning = Math.abs(frequency - targetFreq) / targetFreq;
  const resonanceQuality = Math.max(0, 1 - detuning * 5); // Sharp drop off

  // 3. Calculate Energy Density at Core (Equation 6)
  // E_core scales with 12 channels and Input Amplitude
  // E_core ~ 12 * A_input * Resonance / r^2 (at limit)
  // We use a simplified scalar model for the app:
  const base12Multiplier = 12.0;
  // We simulate the 1/r^2 singularity by clamping it to a high "core" value
  const coreEnergyFactor = base12Multiplier * inputAmplitude * resonanceQuality * 100;

  const energyDensity = coreEnergyFactor;

  // 4. Calculate Mass Reduction (Equation 7)
  // M_eff = M0 * (1 - alpha * (E_core / E_vac))
  const reductionRatio = couplingConstant * (energyDensity / VACUUM_AFFINITY_DENSITY);

  // Clamp reduction to max 1.0 (100%) for physical safety in simulation
  const effectiveRatio = Math.min(1.0, Math.max(0, reductionRatio));

  const effectiveMass = INITIAL_MASS_KG * (1.0 - effectiveRatio);
  const massReductionPercent = effectiveRatio * 100;

  return {
    waveNumber: k,
    resonanceQuality,
    energyDensity,
    effectiveMass,
    massReductionPercent,
    isLevitating: massReductionPercent > 95
  };
};

import { GoogleGenAI } from "@google/genai";
import { SYSTEM_INSTRUCTION } from "../constants";

let ai: GoogleGenAI | null = null;

if (process.env.API_KEY) {
  ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
}

export const sendMessageToDrRipley = async (message: string): Promise<string> => {
  if (!ai) {
    return "Dr. Ripley is currently offline (API Key missing). Please check your connection to the QAG network.";
  }

  try {
    const modelId = "gemini-3-flash-preview";
    const response = await ai.models.generateContent({
      model: modelId,
      contents: message,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      },
    });

    return response.text || "The equations are unclear at this moment.";
  } catch (error) {
    console.error("QAG Transmission Error:", error);
    return "Interference detected in the Affinity Field. Unable to process query.";
  }
};

import React, { useEffect, useRef } from 'react';
import { PhysicsResult } from '../types';

interface ResonatorVizProps {
  physics: PhysicsResult;
  inputAmplitude: number;
}

const ResonatorViz: React.FC<ResonatorVizProps> = ({ physics, inputAmplitude }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let time = 0;

    const render = () => {
      time += 0.05 + (physics.resonanceQuality * 0.1);
      const width = canvas.width;
      const height = canvas.height;
      const centerX = width / 2;
      const centerY = height / 2;
      const radius = Math.min(width, height) * 0.35;

      // Clear
      ctx.clearRect(0, 0, width, height);

      // Draw background glow based on energy density
      const glowIntensity = Math.min(1, physics.energyDensity / 2000);
      const gradient = ctx.createRadialGradient(centerX, centerY, 5, centerX, centerY, radius * 1.5);
      gradient.addColorStop(0, `rgba(56, 189, 248, ${0.2 + glowIntensity * 0.8})`);
      gradient.addColorStop(0.5, `rgba(15, 23, 42, 0.5)`);
      gradient.addColorStop(1, 'rgba(15, 23, 42, 0)');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, width, height);

      // Draw the Base-12 Channels (The Topological Constraint)
      ctx.save();
      ctx.translate(centerX, centerY);

      // If levitating, shake gently or float up (simulated by scale/offset in a real 3D view, here just pulse)
      if (physics.isLevitating) {
        ctx.translate(0, Math.sin(time * 2) * 5);
      }

      // Draw Outer Shell
      ctx.beginPath();
      ctx.arc(0, 0, radius, 0, Math.PI * 2);
      ctx.strokeStyle = '#94a3b8';
      ctx.lineWidth = 4;
      ctx.stroke();

      // Draw 12 Channels
      for (let i = 0; i < 12; i++) {
        const angle = (i * Math.PI * 2) / 12;
        ctx.rotate(angle);

        // Channel line
        ctx.beginPath();
        ctx.moveTo(0, 0);
        ctx.lineTo(radius, 0);
        ctx.strokeStyle = `rgba(148, 163, 184, 0.3)`;
        ctx.lineWidth = 1;
        ctx.stroke();

        // Wave packets traveling inward
        // Only show if there is input
        if (inputAmplitude > 0) {
            const waveCount = 3;
            for(let w=0; w<waveCount; w++) {
                const speed = 1 + physics.resonanceQuality * 2;
                // Waves move from radius to 0
                const wavePos = (time * speed + w * (radius/waveCount)) % radius;
                const currentR = radius - wavePos; // Moving inward

                // Opacity increases near center (Focusing effect)
                const opacity = (1 - (currentR/radius)) * inputAmplitude * 0.1;

                ctx.beginPath();
                ctx.arc(currentR, 0, 2, 0, Math.PI*2);
                ctx.fillStyle = `rgba(56, 189, 248, ${opacity})`;
                ctx.fill();
            }
        }

        ctx.rotate(-angle);
      }

      // Draw The Core (Singularity)
      const coreSize = 10 + (physics.energyDensity / 100);
      const coreAlpha = Math.min(1, physics.energyDensity / 1000);

      ctx.beginPath();
      ctx.arc(0, 0, coreSize, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(251, 191, 36, ${coreAlpha})`; // Gold core
      ctx.shadowBlur = 20 * coreAlpha;
      ctx.shadowColor = '#fbbf24';
      ctx.fill();
      ctx.shadowBlur = 0;

      // Label
      if (physics.isLevitating) {
          ctx.font = 'bold 16px monospace';
          ctx.fillStyle = '#22c55e';
          ctx.textAlign = 'center';
          ctx.fillText("LEVITAION ACHIEVED", 0, radius + 40);
      }

      ctx.restore();

      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => cancelAnimationFrame(animationFrameId);
  }, [physics, inputAmplitude]);

  return (
    <div className="relative w-full aspect-square max-w-md mx-auto bg-qag-panel rounded-xl border border-slate-700 shadow-2xl overflow-hidden">
      <div className="absolute top-2 left-4 text-xs font-mono text-slate-400">
        FIG 1. BASE-12 TOPOLOGY
      </div>
      <canvas 
        ref={canvasRef} 
        width={400} 
        height={400} 
        className="w-full h-full"
      />
    </div>
  );
};

export default ResonatorViz;

